function preloader(){try{document.body.onload=function(){setTimeout((()=>{const e=document.getElementById("preloader");e.classList.contains("done")||e.classList.add("done")}),500)}}catch{console.error()}}function burgerMenu(){try{const e=document.querySelector(".burger-icon"),t=document.querySelector(".burger__button"),o=document.querySelector(".navbar");t.addEventListener("click",(function(){document.body.classList.toggle("_lock"),e.classList.toggle("open"),o.classList.toggle("active")}))}catch{console.log(error)}}function menuLink(){const e=document.querySelectorAll("#item"),t=document.querySelector(".burger__button"),o=document.querySelector(".burger-icon"),c=document.querySelector(".navbar"),n=document.querySelector(".header__button");e.forEach((e=>{e.addEventListener("click",(function(e){document.body.classList.remove("_lock"),t.classList.remove("active"),c.classList.remove("active"),o.classList.remove("open")}))})),n.addEventListener("click",(function(){document.body.classList.remove("_lock"),o.classList.toggle("open"),c.classList.toggle("active")}))}function year(){try{document.querySelector("#year").textContent=(new Date).getFullYear()}catch{console.log(error)}}function swiperSlider(){new Swiper(".swiperPromo",{navigation:{nextEl:".next",prevEl:".prev"},direction:"horizontal",loop:!0,spaceBetween:0,mousewheelControl:!1,slidesPerView:1})}function accordionFaq(){const e=document.querySelectorAll(".faq__item-question");e.forEach((function(t){t.addEventListener("click",(function(){var o=t.classList.contains("active");e.forEach((function(e){e.classList.remove("active")})),t.classList.toggle("active",!o);var c=t.querySelector(".answer"),n=t.querySelector(".dot");document.querySelectorAll(".answer, .dot").forEach((function(e){e.classList.remove("active")})),c&&!o&&c.classList.add("active"),n&&!o&&n.classList.add("active")}))}))}function changeLanguage(e){try{const e=document.querySelectorAll(".switcher-language__item");e.forEach((function(t){t.addEventListener("click",(()=>{e.forEach((function(e){e.classList.remove("active")})),t.classList.toggle("active")}))}))}catch{console.log(error)}}function translator(){const e={ru:{welcomes:"Crypto town Приветствует тебя!"},ua:{welcomes:"Crypto town Вітає тебе!"},en:{welcomes:"Crypto town Welcomes you!"}};document.querySelectorAll(".switcher-language__item").forEach((function(t){t.addEventListener("click",(function(){const o=t.id;document.querySelectorAll(".lang").forEach((function(t){var c=t.getAttribute("key");t.textContent=e[o][c]}))}))}))}function validationForm(){try{new JustValidate("#form").addField(document.querySelector("#name"),[{rule:"required",errorMessage:"Invalid this field is empty"},{rule:"minLength",value:3},{rule:"maxLength",value:15}])}catch{}}validationForm(),preloader(),translator(),burgerMenu(),year(),menuLink(),accordionFaq(),changeLanguage();